304→        private void tmROBOT_Tick(object sender, EventArgs e)
305→        {
306→            switch (st_var.rc_step)
307→            {
308→                case 1000:
309→                    com_open();
310→                    st_var.rc_step = 2000;
311→                    break;
312→
313→                case 2000:
314→                    if (st_var.robot_connected)
315→                    {
316→                        txtTCP_RES.Text = "CONNECT SUCCESS";
317→                        st_var.rc_step = 4000;
318→                    }
319→                    else
320→                    {
321→                        txtTCP_RES.Text = "CONNECT FAIL";
322→                        st_var.rc_step = 20000;
323→                    }
324→                    break;
325→
326→                case 4000:
327→                    st_var.rb_send_msg = st_var.rb_connect_msg;
328→                    txtTCP_SND.Text = st_var.rb_send_msg;
329→                    com_send();
330→                    st_var.rc_step = 5000;
331→                    break;
332→
333→                case 5000:
334→                    if (st_var.robot_com)
335→                    {
336→                        txtTCP_RES.Text = st_var.rb_response_msg;
337→                        st_var.com_check = 0;
338→                        st_var.rc_step = 7000;
339→                    }
340→                    else
341→                    {
342→                        txtTCP_RES.Text = "COMMUNICATION FAIL";
343→                        st_var.rc_step = 20000;
344→                    }
345→                    break;
346→
347→                case 7000:
348→                    st_var.com_check = st_var.com_check + 1;
349→
350→                    if (st_var.rb_response_msg == st_var.rb_reply_msg)
351→                    {
352→                        st_var.rc_step = 9000;
353→                    }
354→                    else
355→                    {
356→                        if (st_var.com_check > st_var.com_check_limit)
357→                        {
358→                            st_var.rc_step = 20000;
359→                        }
360→                    }
361→
362→                    break;
363→
364→                case 9000:
365→                    st_var.rb_send_msg = st_var.rb_cmd_msg;
366→                    txtTCP_SND.Text = st_var.rb_send_msg;
367→                    com_send();
368→                    st_var.rc_step = 10000;
369→                    break;
370→
371→                case 10000:
372→                    if (st_var.robot_com)
373→                    {
374→                        txtTCP_RES.Text = st_var.rb_response_msg;
375→                        st_var.com_check = 0;
376→                        st_var.rc_step = 12000;
377→
378→                    }
379→                    else
380→                    {
381→                        txtTCP_RES.Text = "COMMUNICATION FAIL";
382→                        st_var.rc_step = 20000;
383→                    }
384→                    break;
385→
386→                case 12000:
387→                    st_var.com_check = st_var.com_check + 1;
388→                    if (st_var.rb_response_msg == st_var.rb_cmd_reply_msg)
389→                    {
390→                        st_var.rc_step = 13500;
391→                    }
392→                    else
393→                    {
394→                        if (st_var.com_check > st_var.com_check_limit)
395→                        {
396→                            st_var.rc_step = 20000;
397→                        }
398→                    }
399→                    break;
400→
401→                case 13500:
402→                    if (st_var.rb_has_cmd_data)
403→                    {
404→                        st_var.rc_step = 14000;
405→                    }
406→                    else
407→                    {
408→                        st_var.rc_step = 16200;
409→                    }
410→                    break;
411→
412→                case 14000:
