1100→        private Image<Gray, byte> ExtractCircularROI(Image<Gray, byte> src, Point center, int radius)
1101→        {
1102→            // CREATE MASKE
1103→            Image<Gray, byte> mask = new Image<Gray, byte>(src.Size);
1104→            mask.SetZero();
1105→
1106→            // DRWA CIRCLE ON MASK
1107→            CvInvoke.Circle(
1108→                mask,
1109→                center,
1110→                radius,
1111→                new MCvScalar(255),
1112→                -1);
1113→
1114→            // Result Image
1115→            Image<Gray, byte> result = new Image<Gray, byte>(src.Size);
1116→
1117→            // APPLY MASK
1118→            CvInvoke.BitwiseAnd(src, src, result, mask);
1119→
1120→            return result;
1121→        }
