1123→        private Image<Gray, byte> FindBlobsByContour(Image<Gray, byte> binaryImg)
1124→        {
1125→            VectorOfVectorOfPoint contours = new VectorOfVectorOfPoint();
1126→            Mat hierarchy = new Mat();
1127→
1128→            CvInvoke.FindContours(
1129→                binaryImg,
1130→                contours,
1131→                hierarchy,
1132→                RetrType.External,      // �ܰ� Contour��
1133→                ChainApproxMethod.ChainApproxSimple
1134→            );
1135→
1136→            Image<Gray, byte> result = binaryImg.Clone();
1137→
1138→            List<double> area = new List<double>();
1139→
1140→            for (int i = 0; i < contours.Size; i++)
1141→            {
1142→                area.Add(CvInvoke.ContourArea(contours[i]));
1143→            }
1144→
1145→            int maxIndex = 0;
1146→            double maxValue = area[0];
1147→
1148→            for (int i = 1; i < area.Count; i++)
1149→            {
1150→                if (area[i] > maxValue)
1151→                {
1152→                    maxValue = area[i];
1153→                    maxIndex = i;
1154→                }
1155→            }
1156→
1157→            Rectangle rect = CvInvoke.BoundingRectangle(contours[maxIndex]);
1158→
1159→            int cx = rect.X + rect.Width / 2;
1160→            int cy = rect.Y + rect.Height / 2;
1161→
1162→            CvInvoke.Rectangle(result, rect, new MCvScalar(255, 255, 255), 5);
1163→            CvInvoke.Circle(result, new Point(cx, cy), 20, new MCvScalar(255, 255, 255), -1);
1164→
1165→            st_var.catch_X_position = visionTOrealX2(cy);
1166→            st_var.catch_Y_position = visionTOrealY2(cx);
1167→
1168→            Point display_center = new Point();
1169→            display_center.X = st_var.center_x;
1170→            display_center.Y = st_var.center_y;
1171→
1172→            CvInvoke.Circle(result, display_center, st_var.fit_r, new MCvScalar(255, 255, 255), 5);
1173→
1174→            CvInvoke.Circle(result, display_center, st_var.out_r, new MCvScalar(255, 255, 255), 5);
1175→
1176→            return result;
1177→
1178→        }
