2059→                    st_var.rb_cmd_reply_msg = "OK: IMOV\r\n";
2060→                    st_var.rb_has_cmd_data = true;
2061→                    st_var.rb_cmddata_msg = st_var.move_cmd + "\r";
2062→                    st_var.rb_cd_reply_format = 3;
2063→
2064→                    if (!tmROBOT.Enabled) { tmROBOT.Enabled = true; }
2065→
2066→                    st_var.crt4_cnt = 0;
2067→                    st_var.correct_step = 29000;
2068→
2069→                    break;
2070→
2071→                case 29000:
